<template><app-content class="h-panel payroll-page"><div class="h-panel-bar"><span class="h-panel-title">薪资项目</span></div><div class="margin-top margin-left payroll-toolbar"><Button color="primary" @click="openForm()">新增</Button><Button @click="initItems">初始化默认项目</Button><Button @click="loadList">刷新</Button></div><div class="h-panel-body"><Table :datas="datas" :border="true"><TableItem title="编码" prop="itemCode"></TableItem><TableItem title="名称" prop="itemName"></TableItem><TableItem title="类型" prop="itemType"></TableItem><TableItem title="公式" prop="formula"></TableItem><TableItem title="费用科目" prop="expenseSubjectId"></TableItem><TableItem title="应付/代扣科目" prop="payableSubjectId"></TableItem><TableItem title="操作" :width="120" align="center"><div class="actions" slot-scope="{data}"><span @click="openForm(data)">编辑</span><span @click="remove(data)">删除</span></div></TableItem></Table></div><Modal v-model="showForm" type="drawer-right" hasCloseIcon><div slot="header">薪资项目</div><Form v-width="480" :labelWidth="120" :model="form"><FormItem label="项目编码"><input v-model="form.itemCode"></FormItem><FormItem label="项目名称"><input v-model="form.itemName"></FormItem><FormItem label="项目类型"><Select v-model="form.itemType" :datas="typeOptions"></Select></FormItem><FormItem label="计算公式"><textarea v-model="form.formula" rows="3"></textarea></FormItem><FormItem label="排序"><NumberInput v-model="form.sortNo"></NumberInput></FormItem><FormItem label="费用科目ID"><NumberInput v-model="form.expenseSubjectId"></NumberInput></FormItem><FormItem label="应付/代扣科目ID"><NumberInput v-model="form.payableSubjectId"></NumberInput></FormItem><FormItem label="启用"><h-switch v-model="form.enabled"></h-switch></FormItem></Form><div class="text-center"><Button color="green" @click="submit">保存</Button><Button @click="showForm=false">取消</Button></div></Modal></app-content></template>
<script>import payroll from '../../api/payroll'; export default { name: 'PayrollItems', data() { return {datas: [], showForm: false, form: {}, typeOptions: [{title: '应发', key: 'EARNING'}, {title: '扣款', key: 'DEDUCTION'}, {title: '实发', key: 'NET'}, {title: '公司承担', key: 'COMPANY'}]} }, methods: { loadList() { payroll.item.list().then(({data}) => this.datas = data || []) }, initItems() { payroll.item.init().then(() => this.loadList()) }, openForm(row) { this.form = row ? Object.assign({}, row) : {enabled: true, itemType: 'EARNING', sortNo: 10}; this.showForm = true }, submit() { const api = this.form.id ? payroll.item.update : payroll.item.save; api(this.form).then(() => { this.showForm = false; this.loadList() }) }, remove(row) { payroll.item.delete(row.id).then(() => this.loadList()) } }, mounted() { this.loadList() } }</script>
<style scoped>.payroll-toolbar button{margin-right:8px}.actions span{margin:0 5px;color:#3788ee;cursor:pointer}textarea{width:100%}</style>
